-- Postcondition: rowcounts must exactly match the plan, or the whole run aborts.
DO $$
DECLARE
  cluster_count integer;
  member_count integer;
BEGIN
  SELECT count(*) INTO cluster_count FROM property_clusters;
  IF cluster_count <> 177 THEN
    RAISE EXCEPTION 'POSTCONDITION FAILED: expected % property_clusters, found %', 177, cluster_count;
  END IF;
  SELECT count(*) INTO member_count FROM property_cluster_members;
  IF member_count <> 177 THEN
    RAISE EXCEPTION 'POSTCONDITION FAILED: expected % property_cluster_members, found %', 177, member_count;
  END IF;
END $$;

COMMIT;
